// Полу// Получаем входные данные
const items = $input.all();

// Массив для результата
const result = [];

// Обрабатываем каждый элемент
for (const item of items) {
  try {
    // Получаем данные статьи
    const article = item.json.article;
    const properties = article.properties.properties;

    // Извлекаем нужные поля
    const id = article.id;
    const fullName = properties.author?.fullName || '';
    const title = article.title || properties.title?.text || '';

    // Извлекаем даты дедлайна
    let deadlineFrom = '';
    let deadlineTo = '';

    if (properties.executionDate) {
      deadlineFrom = properties.executionDate.from || '';
      deadlineTo = properties.executionDate.to || '';
    }

    // Формируем текст дедлайна
    let deadlineText = '';
    if (deadlineFrom && deadlineTo) {
      deadlineText = `с ${deadlineFrom} по ${deadlineTo}`;
    } else if (deadlineFrom) {
      deadlineText = `с ${deadlineFrom}`;
    } else if (deadlineTo) {
      deadlineText = `по ${deadlineTo}`;
    }

    // Добавляем в результат
    result.push({
      id: id,
      fullName: fullName,
      deadlineText: deadlineText,
      title: title,
      executionDate: {
        from: deadlineFrom,
        to: deadlineTo
      }
    });

  } catch (error) {
    // В случае ошибки пропускаем элемент или добавляем информацию об ошибке
    console.error('Ошибка обработки элемента:', error);
  }
}

// Возвращаем результат
return result;

