function normalizeName(name) {
  if (!name) return '';
  return name.trim().replace(/\s+/g, ' ');
}

// Функция для поиска tgid по имени с учетом частичного совпадения
function findTgId(fullName) {
  if (!fullName) return null;

  const normalizedName = normalizeName(fullName);

  // Прямое совпадение
  if (tgidMap[normalizedName]) {
    return tgidMap[normalizedName];
  }

  // Поиск по частичному совпадению (если имя содержит фамилию или часть)
  for (const [name, tgid] of Object.entries(tgidMap)) {
    if (normalizedName.includes(name) || name.includes(normalizedName)) {
